+
+const TAG = 'AppOpenSourceListItemComponent';
+
+@Reusable
+@Component
+export struct AppOpenSourceListItemComponent {
+  @State appInfo: AppInfo = new AppInfo();
+  @Link touchItem: AppInfo | undefined;
+  touchBackgroundColor: ResourceColor = $r('app.color.color_1A000000_grey');
+  strokeWidth: Length = '0.5vp';
+  color: ResourceColor = $r('sys.color.ohos_id_color_list_separator');
+  startMargin: Length = '12vp';
+  endMargin: Length = '12vp';
+
+  @Styles
+  normalStateIconStyles() {
+    .backgroundColor(Color.Transparent)
+    .borderRadius(0)
+  }
+
+  @Styles
+  pressedStateIconStyles() {
+    .backgroundColor((DeviceUtil.isDevicePhone() || DeviceUtil.isDevicePad()) ?
+    $r('sys.color.ohos_id_color_click_effect') : null)
+  }
+
+  aboutToReuse(params: Record<string, ESObject>): void {
+    this.appInfo = params.appInfo as AppInfo;
+    this.touchItem = params.touchItem as AppInfo | undefined;
+    this.touchBackgroundColor = params.touchBackgroundColor as ResourceColor;
+  }
+
+  build() {
+    Column() {
+      Flex({
+        direction: FlexDirection.Row,
+        justifyContent: FlexAlign.SpaceBetween,
+        alignItems: ItemAlign.Center
+      }) {
+        Row() {
+          Text(this.appInfo.label)
+            .fontColor($r('sys.color.ohos_id_color_text_primary'))
+            .fontWeight(FontWeight.Medium)
