+          'title': this.appInfo.label,
+          'licenseFilePath': this.appInfo.licenseFilePath,
+        };
+        const pushParam: PushParam = new PushParam(obj);
+        PageRouter.push(NavEntryKey.APP_OPEN_SOURCE_SHOW, pushParam);
+      });
+    })
+  }
